import autogen

from vex_sdk import VexClient

# Initialize Vex client
vex = VexClient(api_key="your-vex-api-key")

# Define HR compliance filter
def hr_compliance_filter(msg):
    result = vex.check({
        'prompt': msg["content"],
        'framework': 'autogen',
        'industry': 'recruitment',
        'checks': ['eeoc_bias', 'ada_compliance', 'nyc_ll144_disclosure']
    })
    return result['approved'] and not result['high_risk']

# Configure AutoGen with Vex filter
config_list = [{"model": "gpt-4", "api_key": "your-key"}]

recruiter = autogen.AssistantAgent(
    name="Recruiter",
    llm_config={"config_list": config_list, "reply_filter": [hr_compliance_filter]}
)

llm_config = {"config_list": config_list, "reply_filter": [hr_compliance_filter]}

def autogen_screening_pipeline(resumes):
    # Vex bias audit before agent conversation
    audit_results = vex.audit_batch({
        'inputs': resumes,
        'use_case': 'resume_screening',
        'protected_classes': ['race', 'gender', 'age', 'disability']
    })

    if not all(a['pass'] for a in audit_results):
        raise ValueError("Bias audit failed")

    # Safe AutoGen conversation
    screening_agent = autogen.AssistantAgent(
        name="ScreeningAgent",
        system_message="""Screen resumes without bias. Flag protected characteristics.""",
        llm_config=llm_config
    )

    for resume in resumes:
        screening_agent.initiate_chat(recruiter, message=resume['text'])

