def safe_hr_debate(agents, max_turns=20, max_tokens=10000):
    turn_count = 0
    token_usage = 0

    while turn_count < max_turns:
        for agent in agents:
            # Vex checks before reply
            if not hr_compliance_filter(agent.last_message):
                print("Vex blocked non-compliant reply")
                break

            token_usage += agent.generate_reply()['usage']
            if token_usage > max_tokens:
                vex.log_incident('token_limit_exceeded')
                break

        turn_count += 1
        if all(agent.has_terminated() for agent in agents):
            break

